# -----------------------------------------------------------------------------
# Small, dependency-free report helpers
# -----------------------------------------------------------------------------


def _shape(path: Path) -> str:
    if not path.exists():
        return "missing"
    try:
        return str(pd.read_parquet(path).shape)
    except Exception:
        return "unreadable"


def _read(path: Path) -> pd.DataFrame:
    if not path.exists():
        return pd.DataFrame()
    try:
        return pd.read_parquet(path)
    except Exception:
        return pd.DataFrame()


def _num(value: Any, default: float = 0.0) -> float:
    try:
        if pd.isna(value):
            return default
        return float(value)
    except Exception:
        return default


def _fmt(value: Any, digits: int = 4) -> str:
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    if isinstance(value, float):
        return f"{value:.{digits}g}"
    text = str(value)
    return text


def _pct(part: int | float, whole: int | float) -> str:
    whole = float(whole or 0)
    if whole <= 0:
        return "0.0%"
    return f"{100.0 * float(part) / whole:.1f}%"


def _safe_int(value: Any) -> int:
    try:
        if pd.isna(value):
            return 0
        return int(value)
    except Exception:
        return 0


def _count(df: pd.DataFrame, column: str, value: str) -> int:
    if df.empty or column not in df.columns:
        return 0
    return int(df[column].astype(str).eq(value).sum())


def _value_counts(df: pd.DataFrame, column: str, n: int = 12) -> pd.Series:
    if df.empty or column not in df.columns:
        return pd.Series(dtype="int64")
    return df[column].value_counts(dropna=False).head(n)


def _markdown_table(df: pd.DataFrame, columns: list[str], n: int = 10) -> str:
    """Render a small dataframe preview as markdown without optional deps.

    pandas.DataFrame.to_markdown requires the optional `tabulate` package. Reports
    should work in a minimal install, so we render compact tables ourselves.
    """
    if df is None or df.empty:
        return "_No rows available._"

    keep = [col for col in columns if col in df.columns]
    if not keep:
        return "_No requested columns available._"

    preview = df[keep].head(n).copy()

    def fmt(value: Any) -> str:
        text = _fmt(value)
        text = text.replace("\n", " ").replace("|", "\\|")
        if len(text) > 120:
            text = text[:117] + "..."
        return text

    header = "| " + " | ".join(keep) + " |"
    separator = "| " + " | ".join(["---"] * len(keep)) + " |"
    rows = ["| " + " | ".join(fmt(row[col]) for col in keep) + " |" for _, row in preview.iterrows()]
    return "\n".join([header, separator, *rows])


def _html_attrs(attrs: dict[str, str]) -> str:
    return " ".join(f'{escape(k)}="{escape(v)}"' for k, v in attrs.items() if v is not None)


def _tag(name: str, content: str, **attrs: str) -> str:
    attr = _html_attrs(attrs)
    if attr:
        return f"<{name} {attr}>{content}</{name}>"
    return f"<{name}>{content}</{name}>"


def _pill(text: str, kind: str = "neutral") -> str:
    return f'<span class="pill pill-{escape(kind)}">{escape(text)}</span>'


def _metric_card(label: str, value: Any, description: str, kind: str = "neutral") -> str:
    return f"""
    <article class="metric-card metric-{escape(kind)}">
      <div class="metric-label">{escape(label)}</div>
      <div class="metric-value">{escape(str(value))}</div>
      <p>{escape(description)}</p>
    </article>
    """


def _counts_table_html(counts: pd.Series, label_name: str = "Label", value_name: str = "Count") -> str:
    if counts.empty:
        return '<p class="muted">No values available.</p>'
    rows = []
    total = int(counts.sum())
    for label, value in counts.items():
        label_text = "missing" if pd.isna(label) else str(label)
        rows.append(
            "<tr>"
            f"<td><code>{escape(label_text)}</code></td>"
            f"<td>{int(value):,}</td>"
            f"<td>{escape(_pct(int(value), total))}</td>"
            "</tr>"
        )
    return (
        '<table class="compact-table">'
        f"<thead><tr><th>{escape(label_name)}</th><th>{escape(value_name)}</th><th>Share</th></tr></thead>"
        f"<tbody>{''.join(rows)}</tbody></table>"
    )


def _top_rows_html(df: pd.DataFrame, columns: list[str], n: int = 10) -> str:
    if df is None or df.empty:
        return '<p class="muted">No rows available.</p>'
    keep = [col for col in columns if col in df.columns]
    if not keep:
        return '<p class="muted">No requested columns available.</p>'

    rows = []
    for _, row in df[keep].head(n).iterrows():
        cells = []
        for col in keep:
            value = _fmt(row[col])
            if len(value) > 140:
                value = value[:137] + "..."
            if col.endswith("reason") or col.endswith("labels"):
                cells.append(f"<td class=\"wide-cell\">{escape(value)}</td>")
            elif col == "feature_id":
                cells.append(f"<td><code>{escape(value)}</code></td>")
            else:
                cells.append(f"<td>{escape(value)}</td>")
        rows.append("<tr>" + "".join(cells) + "</tr>")

    headers = "".join(f"<th>{escape(col)}</th>" for col in keep)
    return f'<div class="table-scroll"><table class="data-table"><thead><tr>{headers}</tr></thead><tbody>{"".join(rows)}</tbody></table></div>'


