def _artifact_warnings(cards: pd.DataFrame) -> list[str]:
    if cards.empty:
        return ["- Feature cards are missing; run the `cards` step first."]

    lines: list[str] = []
    n_cards = len(cards)

    artifacts = _count(cards, "primary_label", "likely_artifact")
    if artifacts:
        lines.append(
            f"- `{artifacts}` / `{n_cards}` features are labeled `likely_artifact` ({_pct(artifacts, n_cards)}); inspect them before semantic claims."
        )

    if "artifact_score" in cards.columns:
        artifact_score = pd.to_numeric(cards["artifact_score"], errors="coerce")
        high = int((artifact_score >= 0.35).sum())
        if high:
            lines.append(f"- `{high}` features have artifact score >= 0.35.")

    if not lines:
        lines.append("- No strong artifact warning was detected by the current heuristic triage.")

    return lines


