def _relative_report_path(report_dir: Path, path: str | Path) -> str:
    path = Path(path)
    try:
        return str(path.relative_to(report_dir))
    except Exception:
        if path.parent.name in {"plots", "tables"}:
            return f"{path.parent.name}/{path.name}"
        return str(path)


def _plot_card(report_dir: Path, name: str, path: str) -> str:
    title, description, group = PLOT_CATALOG.get(name, (name.replace("_", " ").title(), "Generated diagnostic plot.", "Other"))
    rel = _relative_report_path(report_dir, path)
    return f"""
    <article class="plot-card" data-group="{escape(group)}">
      <a href="{escape(rel)}"><img src="{escape(rel)}" alt="{escape(title)}" loading="lazy" /></a>
      <div class="plot-body">
        <div class="plot-kicker">{escape(group)}</div>
        <h3>{escape(title)}</h3>
        <p>{escape(description)}</p>
      </div>
    </article>
    """


def _table_card(report_dir: Path, name: str, path: str) -> str:
    title, description, group = TABLE_CATALOG.get(name, (name.replace("_", " ").title(), "Generated table preview.", "Other"))
    rel = _relative_report_path(report_dir, path)
    return f"""
    <article class="artifact-card">
      <div class="artifact-kicker">{escape(group)}</div>
      <h3>{escape(title)}</h3>
      <p>{escape(description)}</p>
      <a class="button-link" href="{escape(rel)}">Open table</a>
    </article>
    """


def _artifact_card(title: str, description: str, path: Path) -> str:
    status = _shape(path)
    return f"""
    <article class="artifact-card">
      <h3>{escape(title)}</h3>
      <p>{escape(description)}</p>
      <div class="artifact-status">Shape/status: <code>{escape(status)}</code></div>
    </article>
    """


def _quick_findings(cards: pd.DataFrame, coverage: pd.DataFrame, alignment: pd.DataFrame, candidates: pd.DataFrame) -> str:
    findings: list[str] = []

    if not cards.empty:
        n = len(cards)
        artifacts = _count(cards, "primary_label", "likely_artifact")
        unlabeled = _count(cards, "primary_label", "unlabeled")
        findings.append(f"{n:,} feature cards were generated; {unlabeled:,} remain unlabeled by conservative triage.")
        if artifacts:
            findings.append(f"{artifacts:,} features are currently likely-artifact candidates and should not be used for semantic claims without inspection.")

    if not alignment.empty and "graph_alignment_bucket" in alignment.columns:
        counts = alignment["graph_alignment_bucket"].value_counts()
        disagreement = _safe_int(counts.get("geometry_coactivation_disagreement", 0))
        strong = _safe_int(counts.get("strong_geometry_coactivation_agreement", 0))
        findings.append(f"Graph alignment found {strong:,} strong geometry/coactivation agreement candidates and {disagreement:,} disagreement cases.")

    if not coverage.empty and "coverage_bucket" in coverage.columns:
        top_bucket = coverage["coverage_bucket"].value_counts().head(1)
        if not top_bucket.empty:
            findings.append(f"Most common residual-coverage bucket: {top_bucket.index[0]} ({int(top_bucket.iloc[0]):,} features).")

    if not candidates.empty:
        findings.append(f"{len(candidates):,} steering-candidate hypotheses were produced for future causal validation.")

    if not findings:
        findings.append("No feature-card artifacts were available. Run the atlas or research preset first.")

    return "<ul>" + "".join(f"<li>{escape(item)}</li>" for item in findings) + "</ul>"


